-- ── ขั้น 5: seed_frequency ─────────────────────────────────────────────────────
-- อัพเดต sort_order ตามความถี่จากไฟล์สถิติ (9 อาการ)

UPDATE "repair_symptoms" SET "sort_order" = 0 WHERE "label_th" ILIKE '%เครื่องรับโทรทัศน์ (%';
UPDATE "repair_symptoms" SET "sort_order" = 1 WHERE "label_th" ILIKE '%เครื่องรับโทรทัศน์ (%';
UPDATE "repair_symptoms" SET "sort_order" = 2 WHERE "label_th" ILIKE '%ตู้เย็นไม่เย็นคอมเพร%';
UPDATE "repair_symptoms" SET "sort_order" = 3 WHERE "label_th" ILIKE '%เครื่องปรับอากาศแอร์%';
UPDATE "repair_symptoms" SET "sort_order" = 4 WHERE "label_th" ILIKE '%คอมพิวเตอร์ไฟไม่เข้า%';
UPDATE "repair_symptoms" SET "sort_order" = 5 WHERE "label_th" ILIKE '%โน้ตบุ๊กเปิดไม่ติด ไ%';
UPDATE "repair_symptoms" SET "sort_order" = 6 WHERE "label_th" ILIKE '%แท็บเล็ทชาร์ตไฟไม่เข%';
UPDATE "repair_symptoms" SET "sort_order" = 7 WHERE "label_th" ILIKE '%เครื่องโทรศัพท์และโท%';
UPDATE "repair_symptoms" SET "sort_order" = 8 WHERE "label_th" ILIKE '%เครื่องโทรศัพท์และโท%';
